generated_oml:
// C3: Physical sensing components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring the motor input current I_M of the first axis"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Primary position encoder attached to the permanent‑magnet synchronous motor, providing motor angle r_M"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox, providing gearbox output angle r_G"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

// C10: Data (raw measurements)
instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Live motor input current I_M with timestamps streamed via MQTT"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTBroker, AssetAdministrationShell
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Measured motor angle r_M with timestamps"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBroker, AssetAdministrationShell
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Measured gearbox output angle r_G with timestamps"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MQTTBroker, AssetAdministrationShell
]

// C11: Enablers
instance MQTTBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker streaming live sensor data (I_M, r_M, r_G, derived torque, angular velocity, acceleration) from the robot to the digital shadow"
    DTDFVocab:enables RealTimeFrictionIdentification, InteractiveDashboardVisualization
]

instance MatlabSimulinkEngine : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution engine for running friction models and calculation models"
    DTDFVocab:enables ContinuousModelUpdating
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell integrating models and data into the digital twin"
    DTDFVocab:enables ContinuousModelUpdating, InteractiveDashboardVisualization
]

instance DashboardApp : DTDFVocab:Enabler [
    base:desc "Dashboard application for interactive visualization of measured and simulated data"
    DTDFVocab:enables InteractiveDashboardVisualization
]

// C6: Services
instance RealTimeFrictionIdentification : DTDFVocab:Service [
    base:desc "Real‑time friction identification (static, kinetic, viscous) for the gearbox using live sensor data"
    DTDFVocab:provides FrictionParameterInsight, ControlAlgorithmUpdateAction
]

instance ContinuousModelUpdating : DTDFVocab:Service [
    base:desc "Continuous multi‑physics‑aware model updating based on incoming data and simulation results"
    DTDFVocab:provides FrictionParameterInsight
]

instance InteractiveDashboardVisualization : DTDFVocab:Service [
    base:desc "Interactive visualization of measured and simulated data in a unified dashboard"
    DTDFVocab:provides MaintenanceDecisionInsight
]

// C17: Insights / Actions
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Derived friction parameters (static, kinetic, viscous) identified from live data and simulations"
]

instance ControlAlgorithmUpdateAction : DTDFVocab:Action [
    base:desc "Update the robot control algorithm with new friction parameters to improve motion accuracy"
    DTDFVocab:IsAutomatic true
]

instance MaintenanceDecisionInsight : DTDFVocab:Insight [
    base:desc "Dashboard insights guiding parameter tuning and maintenance decisions for the first axis"
]

// C10: Models (Simulink)
instance SimulinkFrictionlessModel : DTDFVocab:Model [
    base:desc "Executable Simulink frictionless model of the first axis"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance SimulinkCoulombViscousModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Coulomb–Viscous friction for the gearbox"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance SimulinkStribeckModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Stribeck friction behavior"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance SimulinkDahlModel : DTDFVocab:Model [
    base:desc "Simulink model implementing Dahl friction model"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

instance SimulinkLuGreModel : DTDFVocab:Model [
    base:desc "Simulink model implementing LuGre friction model"
    DTDFVocab:inputTo MatlabSimulinkEngine
]

// Environment and Components
instance FirstAxisEnvironment : DTDFVocab:Environment [
    base:contains PermanentMagnetSynchronousMotor, Gearbox, CycloidalGearbox
]

instance PermanentMagnetSynchronousMotor : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor driving the first axis"
]

instance Gearbox : DTDFVocab:Component [
    base:desc "Gearbox coupling the motor to the cycloidal gearbox"
]

instance CycloidalGearbox : DTDFVocab:Component [
    base:desc "Cycloidal gearbox providing high reduction for the first axis"
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time operation; data are processed as they arrive from the MQTT stream to support online model updating."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A purpose‑driven digital shadow consisting of the asset (first axis), its engineering and simulation models, processing components that consume measured data traces and produce simulated traces, and a dashboard that aggregates and visualizes the results, all conforming to the Digital Shadow Reference Model."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operated stage – the digital shadow is created for the running robot to improve control accuracy during operation."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of each data point to its source and processing model, continuous comparison of simulated friction‑free and friction‑augmented models against measured data to validate model accuracy, and multi‑physics‑aware identification to maintain high fidelity."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted over MQTT; the digital shadow consumes these MQTT messages; Asset Administration Shells provide metadata linking between physical assets and virtual models."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "Use of the Asset Administration Shell (AAS) standard for asset representation and adherence to the Digital Shadow Reference Model (based on UML), aligning with Industry 4.0 standards."
]
